function reverseString(str) {
  return str.split('').reverse().join('');
}

console.log(reverseString('hello'));  // olleh

function findLargest(numbers) {
  let largest = numbers[0];
  for (let num of numbers) {
    if (num > largest) {
      largest = num;
    }
  }
  return largest;
}

console.log(findLargest([3, 7, 2, 9, 1]));  // 9
